* of address one beyond */
data = *( &data + 0 ); /* Compliant - C treats data as an
* array of size 1 */
d[ 3 ][ 1 ] = 0; /* Compliant */
data = *( *( d + 3 ) + 1 ); /* Compliant */
data = d[ 2 ][ 3 ]; /* Non-compliant - undefined, internal
* boundary exceeded */
p1 = d[ 1 ]; /* Compliant */
data = p1[ 1 ]; /* Compliant - p1 addresses an array
* of size 2 */
}
